<script setup lang="ts">import { computed,ref } from 'vue'; import { ElMessage,ElMessageBox } from 'element-plus'; import { http,messageOf } from '@/api/http'; const props=defineProps<{modelValue:boolean}>(),emit=defineEmits(['update:modelValue','done']); const file=ref<File>(),running=ref(false),paused=ref(false),progress=ref(0),speed=ref(0),sessionId=ref(''); const visible=computed({get:()=>props.modelValue,set:v=>emit('update:modelValue',v)}); function choose(e:Event){file.value=(e.target as HTMLInputElement).files?.[0];progress.value=0} function fingerprint(f:File){return `${f.name}:${f.size}:${f.lastModified}`}
async function start(){if(!file.value)return; const f=file.value; try{const config=(await http.get('/uploads/config')).data;if(f.size>config.warningBytes)await ElMessageBox.confirm(`文件大小为 ${format(f.size)}，继续上传？`,'大文件提醒',{confirmButtonText:'继续',cancelButtonText:'取消'});running.value=true;paused.value=false;const init=(await http.post('/uploads/init',{fingerprint:fingerprint(f),originalName:f.name,mimeType:f.type||'application/octet-stream',totalSize:f.size})).data;sessionId.value=init.id;const received=new Set<number>(init.receivedChunks);let sent=received.size*init.chunkSize,startAt=Date.now();for(let i=0;i<init.totalChunks;i++){if(received.has(i))continue;while(paused.value)await new Promise(r=>setTimeout(r,250));const begin=i*init.chunkSize,blob=f.slice(begin,Math.min(begin+init.chunkSize,f.size)),body=new FormData();body.append('chunk',blob);await http.post(`/uploads/${init.id}/chunks/${i}`,body,{timeout:0});sent+=blob.size;progress.value=Math.min(99,Math.round(sent/f.size*100));speed.value=sent/((Date.now()-startAt)/1000)}await http.post(`/uploads/${init.id}/complete`,{},{timeout:0});progress.value=100;ElMessage.success('上传完成');emit('done');visible.value=false}catch(e:any){if(e!=='cancel')ElMessage.error(messageOf(e))}finally{running.value=false}}
function close(){if(running.value){paused.value=true;ElMessage.info('上传已暂停，再次选择同一文件可继续')}visible.value=false} function format(n:number){if(n<1024**2)return`${(n/1024).toFixed(1)} KB`;if(n<1024**3)return`${(n/1024**2).toFixed(1)} MB`;return`${(n/1024**3).toFixed(2)} GB`}</script>
<template><el-dialog v-model="visible" title="上传视频" width="min(520px,92vw)" :before-close="close"><input type="file" accept="video/*" :disabled="running" @change="choose"/><div v-if="file" class="file"><span>{{file.name}}</span><span class="muted">{{format(file.size)}}</span></div><div v-if="running" class="progress"><el-progress :percentage="progress"/><span class="muted">{{paused?'已暂停':`${format(speed)}/s`}}</span></div><template #footer><el-button @click="close">关闭</el-button><el-button v-if="running" @click="paused=!paused">{{paused?'继续':'暂停'}}</el-button><el-button type="primary" :disabled="!file||running" @click="start">上传</el-button></template></el-dialog></template>
<style scoped>input{width:100%;padding:30px;border:1px dashed #c7ccd6;border-radius:8px}.file{display:flex;justify-content:space-between;gap:12px;margin-top:14px}.file span:first-child{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.progress{margin-top:18px}</style>
